INSERT INTO knowledge_base (content, category, source) VALUES
('Uşaqlar üçün qayda: 6 yaşa qədər uşaqlar valideynlə eyni otaqda pulsuz qalır. 6-12 yaş arası əlavə çarpayı 30 manatdır.', 'policy', 'synthetic_kb.md'),
('Ev heyvanları yalnız 5 kq-a qədər kiçik itlər üçün icazəlidir, gecəlik əlavə 20 manat. Suite otaqlarda ev heyvanı qadağandır.', 'policy', 'synthetic_kb.md'),
('Siqaret çəkmək bütün otaqlarda qadağandır. Pozuntu halında 100 manat cərimə tutulur. Terrasda ayrılmış zona mövcuddur.', 'policy', 'synthetic_kb.md'),
('Ödəniş üsulları: nağd, Visa/MasterCard, bank köçürməsi. Rezervasiya zamanı ilk gecənin qiyməti depozit kimi tutulur.', 'policy', 'synthetic_kb.md'),
('Hava limanından otelə transfer 35 manatdır, əvvəlcədən sifariş tələb olunur. Taksi ilə gəliş təxminən 25-30 dəqiqə çəkir.', 'faq', 'synthetic_kb.md'),
('Otelin pulsuz parkinqi var, yer sayı məhduddur. Elektromobil üçün 2 şarj yeri mövcuddur.', 'faq', 'synthetic_kb.md'),
('Səhər yeməyi restoranda 07:00-10:30 arası verilir. Otağa səhər yeməyi sifarişi əlavə 10 manatdır.', 'faq', 'synthetic_kb.md'),
('Fitness zal 24 saat açıqdır, giriş otaq kartı ilədir. Hovuz 07:00-22:00, spa mərkəzi 10:00-21:00 arası işləyir.', 'faq', 'synthetic_kb.md'),
('Spa paketinə 60 dəqiqəlik klassik masaj, türk hamamı və sauna daxildir. Cütlük paketi 140 manatdır.', 'service_desc', 'synthetic_kb.md'),
('Konfrans zalı 80 nəfərlikdir, proyektor və səs sistemi ilə təchiz olunub. Günlük icarə 500 manat, otel qonaqlarına 20% endirim.', 'service_desc', 'synthetic_kb.md'),
('Bal ayı paketi: Suite otaqda 3 gecə, şampan, gül bəzəyi və cütlük spa — 1350 manat əvəzinə 1100 manat.', 'marketing', 'synthetic_kb.md'),
('Erkən rezervasiya endirimi: 30 gün əvvəl bron edənlərə bütün otaq tiplərində 10% endirim tətbiq olunur.', 'marketing', 'synthetic_kb.md');
